public int minLengthAfterOperations(String s) {
    int aCount = s.length() - s.replace("a", "").length();
    int bCount = s.length() - s.replace("b", "").length();
    int cCount = s.length() - s.replace("c", "").length();

    if (aCount % 2 == bCount % 2 && bCount % 2 == cCount % 2) {
        return s.length() % 2;
    }
    return (s.length() + 1) % 2;
}
```

